var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"갓뎀...... 장식들 센스하고는.","JPN":"ガッデム……この飾りは何？　ひっどいセンスだね。","ENG":"Geez, you've got terrible taste in decor.","TWN":"天啊……這裡裝飾得真有品味。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그래서 뭐, 종신 계약? 나하고 그런 걸 맺겠다고?","JPN":"それで？　えっ、終身契約？\\nアタシとそれを結ぼうっての？","ENG":"So, a lifetime contract, huh? You want me to sign for life. Is that it?","TWN":"所以是什麼，終身契約？你要跟我締結這種東西？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"어린양도 어지간히 속이 꼬인 사람이네. 그런 게 매력이지만.","JPN":"迷える子羊クンも、大分ひねくれてた性格してるんだね。ま、そこが魅力だけどさ。","ENG":"Little lamb, you're pretty twisted. That's what make you so charming, though.","TWN":"看來就算是隻小羊羔，內心也很扭曲呢。但你就是那種地方吸引人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"응? 왜? 난 어린양이 마음에 들어.","JPN":"えっ？　どうしたの？\\nアタシ、社長のことは気に入ってるんだよ？","ENG":"Mm? What? I like you, little lamb.","TWN":"嗯？幹嘛？我喜歡小羊啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"로마에선 엄격 진지한 수녀님들 때문에 나까지 노땅이 되는 기분이었다고.","JPN":"ローマでは真面目で厳しいシスター達に囲まれてて、アタシまで老けちゃう気がしてたからさ。","ENG":"When I was in Rome, I felt so old because of all those serious nuns around me.","TWN":"在羅馬的時候，修女們嚴格又死板，害我都要變成老太婆了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그런 곳에서 빼내 준 사람한테 호감 좀 가지는 게 잘못은 아니지. 성모님도 이해해 주실 걸.","JPN":"そこから出してくれた人に好意を持ってしまうのは不可抗力でしょ？\\n聖母様も解ってくれるって。","ENG":"It's not my fault that I'm attracted to the person who saved me from that dreadful place. Even Our Lady would understand me.","TWN":"會對救我脫離那種地方的人產生好感，這也沒什麼不對吧？聖母一定也會理解的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그런데 내가 말이야, 이래 봬도 어엿한 수녀거든?","JPN":"といっても、このアタシだってれっきとしたシスターなわけ。","ENG":"By the way, I may not look it, but I'm a legitimate nun.","TWN":"但是我呀，別看我這樣，我也是個堂堂修女喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"어린양 때문에 환속이라도 하게 되면 끝까지 책임지기다?","JPN":"社長のせいで還俗するはめになったら、最後まで責任持ってもらうからね？","ENG":"If I return to secular life because of you, you'll have to take care of me. Promise?","TWN":"如果因為小羊羔還俗，你可要負責到底喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"물론 그때 가서 발 빼면, 알아서 하시고.","JPN":"もしその時になって知らん顔したら……覚悟してもらうから。","ENG":"You'd better not change your mind later, or else.","TWN":"當然，如果你拋棄我的話，後果自行負責。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};